import React from 'react';
import { LineChart, Line, XAxis, YAxis, CartesianGrid, Tooltip, ResponsiveContainer } from 'recharts';
import { motion } from 'framer-motion';

const QueryAnalytics = ({ data }: { data: any }) => {
    if (!data || !data.historical_queries) return null;

    return (
        <div className="flex flex-col h-full">
            <div className="flex justify-between items-start mb-8">
                <div>
                    <p className="text-slate-400 text-[10px] font-mono tracking-widest mb-2 uppercase">QUERY INTELLIGENCE ROUTING</p>
                    <h2 className="text-white text-3xl font-bold tracking-tight">Optimization Active</h2>
                </div>
                <div className="flex items-center gap-2 border border-[#2A2A2A] rounded-full px-3 py-1 bg-[#111]">
                    <span className="w-2 h-2 rounded-full bg-[#ff382e]"></span>
                    <span className="text-[11px] font-mono text-slate-300">RL Pathing</span>
                </div>
            </div>

            <div className="flex-1 min-h-[300px] w-full mt-4">
                <ResponsiveContainer width="100%" height="100%">
                    <LineChart data={data.historical_queries} margin={{ top: 10, right: 10, left: -20, bottom: 0 }}>
                        <XAxis
                            dataKey="time"
                            stroke="#222"
                            fontSize={10}
                            tickLine={false}
                            axisLine={false}
                            dy={10}
                            fontFamily="JetBrains Mono"
                        />
                        <YAxis
                            stroke="#222"
                            fontSize={10}
                            tickLine={false}
                            axisLine={false}
                            fontFamily="JetBrains Mono"
                        />
                        <CartesianGrid strokeDasharray="1 15" stroke="#222" vertical={true} horizontal={true} />
                        <Tooltip
                            contentStyle={{
                                backgroundColor: '#000',
                                border: '1px solid #2A2A2A',
                                borderRadius: '4px',
                                fontSize: '10px',
                                textTransform: 'uppercase',
                                fontFamily: 'JetBrains Mono',
                                color: '#fff'
                            }}
                            itemStyle={{ color: '#fff', padding: 0 }}
                            cursor={{ stroke: '#FFFFFF', strokeWidth: 0.5, strokeDasharray: '4 4' }}
                        />
                        {/* Premium Path (White Dashed) */}
                        <Line
                            type="monotone"
                            dataKey="gpt4"
                            stroke="#FFFFFF"
                            strokeWidth={1}
                            strokeDasharray="2 2"
                            dot={{ fill: '#FFFFFF', r: 3, strokeWidth: 0 }}
                            activeDot={{ r: 5, strokeWidth: 0, fill: '#FFFFFF', shadow: '0 0 10px white' }}
                            name="PREMIUM"
                        />
                        {/* Alternative Path (Gray Solid) */}
                        <Line
                            type="monotone"
                            dataKey="sonnet"
                            stroke="#4a4a4a"
                            strokeWidth={1}
                            dot={false}
                            name="BALANCED"
                        />
                    </LineChart>
                </ResponsiveContainer>
            </div>

            {/* X Axis Range Labels */}
            <div className="flex justify-between px-4 mt-4 text-[10px] font-mono text-slate-500 uppercase">
                <span>START: 0s</span>
                <span>TELEMETRY_STREAM</span>
                <span>END: 5s</span>
            </div>
        </div>
    );
};

export default QueryAnalytics;
